INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0c700c30-moex-00248', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '下列文句「」中的成語，使用最適當的是：', '["接待人員們「前倨後恭」，誠摯歡迎每位與會的嘉賓", "在這寒冷的天氣，樹林一片「枝葉扶疏」的蕭瑟景象", "飯店緊臨港灣，在頂樓可以俯瞰「滄海橫流」的美景", "這家商店的營運狀況已「江河日下」，不能跟以前相比"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00249', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '下列文句「」中的成語，使用最適當的是：', '["面對世事無常，不禁使人產生「曾經滄海」之嘆", "經過一番努力，他終於能「克紹箕裘」，光大門楣", "他向來精打細算，善用「買櫝還珠」的策略而致富", "網路上的諸多訊息，有可能是「爍石流金」的謠言，並非事實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00250', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '下列文句「」中的成語，使用最適當的是：', '["文藝創作不僅需要「天花亂墜」般的才華，同時也要持續不懈地努力，才有可能獲得賞識", "突發性的心血管疾病十分危急，需要急救人員「奮勇爭先」地施以緊急醫療，才有可能挽 回一命", "他面對別人的質疑總能維持「落落大方」的風度，即便對方言詞犀利，也依然能夠虛心接 受別人的建議", "演講時不僅講究臺風的穩健，更要有著「信口雌黃」的功力，才有辦法吸引到大家的目光， 獲得更多掌聲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00251', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「多年後我自己重讀《易經》，愈來愈相信這是一部實用於生命現場的書，它可能啟始於某 一個簡易的神祕公式，但真正的完成靠的卻是人的世故，有點像統計學，收集了人一次次刻 骨銘心的生命經驗和教訓編纂起來。它預言的堅實基礎來自厚厚一疊而非一次的過去，來自 人一再重複類似處境慢慢察覺出來的事物某種慣性和人心某種趨向，這每一種特定的處境， 都一定程度制約窄化了未來，引發著特定的變化乃至於其規律節奏，未來因此有一部分可推 演可猜測。」 根據上文，作者認為《易經》是一部實用於生命現場的書，最主要的原因是：', '["具神祕啟示性質，可占卜人世吉凶", "立足於經驗及人性，具一定準確度", "能推演吉凶，源於堅實的數學運算", "始於神祕公式，可信度被充分驗證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00252', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「投身到任何一個行業，只好埋頭苦幹。有人只看見和尚吃饅頭，沒看見和尚受戒，遂生羨 慕別人之心，以為自己這一行只有苦沒有樂。」 根據上文，下列何者最符合文意？', '["一分生意三分險", "問遍千家是行家", "做一行，怨一行", "道路各別，養家一般"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00253', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「傳話時要記得只傳達雙方領袖的合理意見，而不要把他們加鹽添醋的情緒語言也照樣傳 達。這樣就算談判沒有很成功，也在可以理解的範圍中，而不致成為老闆情緒挫折的替罪 羔羊。」 根據上文，傳話者經常被老闆視為替罪羔羊，最主要的原因是：', '["過度虛美的言辭", "明哲保身的態度", "傳達的方式欠妥", "傳遞的訊息有誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00254', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「你何妨就在內心先確定一個廣泛的目標？先在家裡勾畫出完整的憧憬，布置一些可能發生 的情節，以想像的陌生世界為背景，把自己血肉之軀投射進去，堅持自己所追求所要的東西， 然後出門。這樣的旅行說不定會因為一切都不如理想而大失所望，但失望何嘗就不是一件莊 嚴的理由？這樣的旅行是充滿目的和意志的，是學習的歷程，是考驗，是一種探險。」 關於上文，敘述最適當的是：', '["事先做好規劃，就可以擁有理想的旅行", "探險與學習是旅行的目的，即使失望也有其價值", "旅行之前要先預設可能發生的情節，才能避免發生危險", "旅行的過程可能充滿考驗，堅持到底才能算是完成挑戰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00255', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「百里奚押送鹽車到秦國。秦穆公見到拉車的牛很肥壯，問他：『車載著很重的東西，路途 遙遠且多險阻，你的牛為什麼還能這麼肥壯呢？』百里奚回答說：『按時給牠吃飯喝水，駕 車時不粗暴對待牛，碰到危險的地方，我自己緊隨在牠身旁，所以牛才會這麼肥壯。』」 根據上文，百里奚的態度理念，下列何者最契合？', '["機智應變", "仁心愛物", "勇於任事", "共體時艱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00256', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「古人欣賞奇磔遒勁的奇木奇石，大概是因為那奇磔遒勁中隱藏透漏著生命奮鬥的痕跡吧！ 當那掙扎求活的傷痛過去，那掙扎求活的姿態卻成了使人歌讚的對象。」 根據上文，下列何者最符合文意？', '["飽歷滄桑的紋理是生命的印記", "歌詠讚嘆自然造物的鬼斧神工", "木石經過雕琢銘刻方成就藝術", "藝術家投注生命力於木石雕刻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00257', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-34c7f7f6', 'sub-elementary-0c700c30-02', NULL, 'single_choice', '「Instagram上線之初，原本倡導素人攝影，鼓勵用戶記錄『你看到的世界』；然而，幾年下 來，IG主流文化轉變為『以你為核心的世界』，擺拍，設計場景，美肌，非寫實濾鏡，將自 己拼貼在令人驚嘆崇拜的場景裡，設法拍出唱片封套或雜誌封面的人物質感。於是，網紅們 四處尋找無敵海景、值得打卡的店家、適合入鏡的牆面，自我鑲嵌其中，希望一張爆紅照片 能增加上千名追蹤者；直到有一天，數以萬計的追蹤者可以讓自己躋身網路名流，同時藉此 變現。」 關於上文，下列敘述最適當的是：', '["現在的IG主流文化，主要透過商業攝影以賺取流量與金錢", "成為網紅的必要條件之一，是要能忠實記錄自己的日常生活", "IG創設之初鼓勵人以拼貼展示令人羨慕的自己，進而獲得關注", "「以你為核心的世界」，是指創造一個可能脫離現實生活的環境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
